const PNCP_PORTAL_ID = 'cmnatwc8p0001f8xpoefyuokp';

const proposta = $('HTTP PNCP Proposta').all();
const publicacao = $('HTTP PNCP Publicacao').all();

function collect(arr) {
  const out = [];
  for (const e of arr) {
    const rows = e.json?.data || e.json?.contratacoes || [];
    for (const i of rows) {
      const externalId = i.numeroControlePNCP || i.numeroCompra || String(i.id || '');
      if (!externalId) continue;
      const title = (i.objetoCompra || i.descricao || 'Sem titulo').trim();
      const organ = (i.orgaoEntidade?.razaoSocial || i.orgao || 'Nao informado').trim();
      out.push({
        externalId,
        portalId: PNCP_PORTAL_ID,
        title,
        organ,
        state: i.unidadeOrgao?.ufSigla || i.uf || null,
        city: i.unidadeOrgao?.municipioNome || i.municipio || null,
        modality: (i.modalidadeNome || i.modalidade || 'Nao informado').trim(),
        estimatedValue: i.valorTotalEstimado ? Number(i.valorTotalEstimado) : null,
        openingDate: i.dataAberturaProposta ? new Date(i.dataAberturaProposta).toISOString() : null,
        pdfUrl: i.linkSistemaOrigem || i.linkEdital || i.linkProcesso || null,
        rawText: null
      });
    }
  }
  return out;
}

const merged = [...collect(proposta), ...collect(publicacao)];
const seen = new Set();
const dedup = merged.filter(x => {
  if (seen.has(x.externalId)) return false;
  seen.add(x.externalId);
  return true;
});

return dedup.map(i => ({ json: i }));
